/**
 * Canonical color representation used throughout the picker.
 * All values normalized; alpha is always tracked.
 */
export interface OklchColor {
  /** Lightness 0..1 */
  l: number;
  /** Chroma 0..~0.4 (hard upper bound depends on hue + space) */
  c: number;
  /** Hue 0..360 (NaN when chroma === 0; treat as 0 for serialization) */
  h: number;
  /** Alpha 0..1 */
  alpha: number;
}

export type ColorFormat =
  | "hex"
  | "rgb"
  | "hsl"
  | "hsb"
  | "oklch"
  | "oklab"
  | "p3";

export type Gamut = "srgb" | "p3" | "rec2020";

export interface ContrastResult {
  /** WCAG 2.1 contrast ratio, 1..21 */
  wcag: number;
  /** WCAG 2.1 levels passed against the supplied background */
  wcagLevel: { aaNormal: boolean; aaLarge: boolean; aaaNormal: boolean; aaaLarge: boolean };
  /** APCA Lc value, signed, typical magnitude 0..108 */
  apca: number;
}

export interface GamutInfo {
  inSrgb: boolean;
  inP3: boolean;
  inRec2020: boolean;
}

import {
  parse as culoriParse,
  converter,
  formatHex,
  formatHex8,
  formatRgb,
  formatCss,
  toGamut as culoriToGamut,
  wcagContrast,
  type Color,
} from "culori";
import type { ColorFormat, ContrastResult, Gamut, GamutInfo, OklchColor } from "./types";

const toOklch = converter("oklch");
const toRgb = converter("rgb");
const toHsl = converter("hsl");
const toHsv = converter("hsv");
const toOklab = converter("oklab");
const toP3 = converter("p3");

const GAMUT_EPSILON = 1e-4;

function channelsInRange(c: { r?: number; g?: number; b?: number } | undefined): boolean {
  if (!c) return false;
  const r = c.r ?? 0;
  const g = c.g ?? 0;
  const b = c.b ?? 0;
  return (
    r >= -GAMUT_EPSILON && r <= 1 + GAMUT_EPSILON &&
    g >= -GAMUT_EPSILON && g <= 1 + GAMUT_EPSILON &&
    b >= -GAMUT_EPSILON && b <= 1 + GAMUT_EPSILON
  );
}

const toRec2020 = converter("rec2020");

function isInSrgb(ok: { mode: "oklch"; l: number; c: number; h: number; alpha: number }) {
  return channelsInRange(toRgb(ok));
}
function isInP3(ok: { mode: "oklch"; l: number; c: number; h: number; alpha: number }) {
  return channelsInRange(toP3(ok));
}
function isInRec2020(ok: { mode: "oklch"; l: number; c: number; h: number; alpha: number }) {
  return channelsInRange(toRec2020(ok));
}

/**
 * Parse a CSS color string into the canonical OKLCH form.
 * Returns null when the string can't be parsed.
 */
export function parseColor(input: string): OklchColor | null {
  if (!input || typeof input !== "string") return null;
  const parsed = culoriParse(input.trim());
  if (!parsed) return null;
  const oklch = toOklch(parsed);
  if (!oklch) return null;
  return {
    l: clamp(oklch.l ?? 0, 0, 1),
    c: Math.max(oklch.c ?? 0, 0),
    h: Number.isFinite(oklch.h) ? (oklch.h as number) : 0,
    alpha: oklch.alpha ?? 1,
  };
}

export function isValidColor(input: string): boolean {
  return parseColor(input) !== null;
}

/** Convert canonical OKLCH back to a culori Color in the requested mode. */
function toCulori(c: OklchColor, mode: "oklch" | "rgb" | "p3" | "oklab" | "hsl" | "hsv") {
  const base = { mode: "oklch" as const, l: c.l, c: c.c, h: c.h, alpha: c.alpha };
  switch (mode) {
    case "oklch":
      return base;
    case "rgb":
      return toRgb(base);
    case "p3":
      return toP3(base);
    case "oklab":
      return toOklab(base);
    case "hsl":
      return toHsl(base);
    case "hsv":
      return toHsv(base);
  }
}

/**
 * Serialize a canonical OKLCH color to a CSS string in the chosen format.
 * For sRGB-targeted formats (hex/rgb/hsl/hsb) the color is gamut-mapped to sRGB first.
 * For P3 the color is gamut-mapped to P3.
 * OKLCH/OKLab outputs are unbounded.
 */
export function formatColor(color: OklchColor, format: ColorFormat): string {
  switch (format) {
    case "hex": {
      const mapped = mapToGamutColor(color, "srgb");
      const rgb = toRgb({ mode: "oklch", ...oklchObj(mapped) });
      if (!rgb) return "#000000";
      return (color.alpha < 1 ? formatHex8(rgb) : formatHex(rgb)).toUpperCase();
    }
    case "rgb": {
      const mapped = mapToGamutColor(color, "srgb");
      const rgb = toRgb({ mode: "oklch", ...oklchObj(mapped) });
      return rgb ? formatRgb(rgb) : "rgb(0 0 0)";
    }
    case "hsl": {
      const mapped = mapToGamutColor(color, "srgb");
      const hsl = toHsl({ mode: "oklch", ...oklchObj(mapped) });
      return hsl ? formatCss(hsl) : "hsl(0 0% 0%)";
    }
    case "hsb": {
      const mapped = mapToGamutColor(color, "srgb");
      const hsv = toHsv({ mode: "oklch", ...oklchObj(mapped) });
      if (!hsv) return "hsv(0 0% 0%)";
      // CSS does not standardize hsb(); emit hsv() (alias) for clarity, but tests just check parseable
      return formatCss(hsv);
    }
    case "oklch": {
      const { l, c, h, alpha } = color;
      const lStr = round(l, 4);
      const cStr = round(c, 4);
      const hStr = round(h, 2);
      return alpha < 1
        ? `oklch(${lStr} ${cStr} ${hStr} / ${round(alpha, 3)})`
        : `oklch(${lStr} ${cStr} ${hStr})`;
    }
    case "oklab": {
      const lab = toOklab({ mode: "oklch", ...oklchObj(color) });
      return lab ? formatCss(lab) : "oklab(0 0 0)";
    }
    case "p3": {
      const mapped = mapToGamutColor(color, "p3");
      const p3 = toP3({ mode: "oklch", ...oklchObj(mapped) });
      return p3 ? formatCss(p3) : "color(display-p3 0 0 0)";
    }
  }
}

/** Convenience: pull bare OKLCH numeric fields. */
function oklchObj(c: OklchColor) {
  return { l: c.l, c: c.c, h: c.h, alpha: c.alpha };
}

const ALL_FORMATS: ColorFormat[] = [
  "hex",
  "rgb",
  "hsl",
  "hsb",
  "oklch",
  "oklab",
  "p3",
];

/**
 * Serialize an OKLCH color to every supported output format at once.
 * Useful when consumers need both the canonical lossless form (oklch) and
 * a fallback string (hex) without re-running format selection.
 */
export function formatAll(color: OklchColor): Record<ColorFormat, string> {
  const out = {} as Record<ColorFormat, string>;
  for (const f of ALL_FORMATS) out[f] = formatColor(color, f);
  return out;
}

/**
 * Continuous signed distance from the target gamut surface.
 *  - 0 on the boundary
 *  - <0 inside the gamut (any channel exceeds [0,1] by the most-negative amount)
 *  - >0 outside the gamut (channels exceed by the most-positive amount)
 *
 * Drives the marching-squares boundary line. We use inline OKLab → linear RGB
 * math (zero crossings unchanged from gamma-encoded RGB) so the per-grid-point
 * cost stays under a microsecond — at 128² × 2 lines per OKLCH-mode repaint
 * the culori path was the new perf hot spot.
 */
export function gamutSignedDistance(color: OklchColor, gamut: Gamut): number {
  const lin = oklchToLinearSrgb(color.l, color.c, color.h);
  const target =
    gamut === "srgb"
      ? lin
      : gamut === "p3"
        ? linSrgbToLinP3(lin)
        : linSrgbToLinRec2020(lin);
  const lo = -Math.min(target.r, target.g, target.b);
  const hi = Math.max(target.r, target.g, target.b) - 1;
  return Math.max(lo, hi);
}

/**
 * OKLCH → linear sRGB via Björn Ottosson's OKLab matrix. Output channels can
 * be negative or >1 for colors outside sRGB; that's the point — wider gamuts
 * are just `linSrgbToLinP3` / `linSrgbToLinRec2020` away.
 */
export function oklchToLinearSrgb(
  l: number,
  c: number,
  hDeg: number,
): { r: number; g: number; b: number } {
  const h = (hDeg * Math.PI) / 180;
  const a = c * Math.cos(h);
  const b = c * Math.sin(h);

  const lp = l + 0.3963377774 * a + 0.2158037573 * b;
  const mp = l - 0.1055613458 * a - 0.0638541728 * b;
  const sp = l - 0.0894841775 * a - 1.291485548 * b;

  const L = lp * lp * lp;
  const M = mp * mp * mp;
  const S = sp * sp * sp;

  return {
    r: 4.0767416621 * L - 3.3077115913 * M + 0.2309699292 * S,
    g: -1.2684380046 * L + 2.6097574011 * M - 0.3413193965 * S,
    b: -0.0041960863 * L - 0.7034186147 * M + 1.707614701 * S,
  };
}

/* Linear sRGB → linear Display-P3 (CSS Color 4 reference matrix). */
export function linSrgbToLinP3(c: {
  r: number;
  g: number;
  b: number;
}): { r: number; g: number; b: number } {
  return {
    r: 0.8224621 * c.r + 0.1775380 * c.g + 0.0 * c.b,
    g: 0.0331942 * c.r + 0.9668058 * c.g + 0.0 * c.b,
    b: 0.0170828 * c.r + 0.0723976 * c.g + 0.9105196 * c.b,
  };
}

/* Linear sRGB → linear Rec.2020 (CSS Color 4 reference matrix). */
export function linSrgbToLinRec2020(c: {
  r: number;
  g: number;
  b: number;
}): { r: number; g: number; b: number } {
  return {
    r: 0.6274039 * c.r + 0.3292830 * c.g + 0.0433131 * c.b,
    g: 0.0690973 * c.r + 0.9195404 * c.g + 0.0113623 * c.b,
    b: 0.0163914 * c.r + 0.0880133 * c.g + 0.8955953 * c.b,
  };
}

/**
 * Bisect for the maximum OKLCH chroma at this lightness and hue that still
 * fits inside the target gamut. Returns 0 at L=0 or L=1 (those are achromatic
 * by definition). Cost: ~12 iterations × 3 matrix-mults per call.
 *
 * `epsilon` controls the bisection's strictness — a positive value relaxes
 * the in-gamut check (allows channels out by `epsilon`); zero is strict; a
 * negative value shrinks the gamut. Default 0 is strict so the returned
 * chroma is *guaranteed* in-gamut; the area's bead-clamp re-pin and
 * culori-based `gamutInfo` (which use their own `GAMUT_EPSILON` tolerance)
 * will then never tip the picked color out.
 *
 * The `marginalChroma` knob trims an absolute amount off the final result
 * to absorb bisection precision (~5e-5) plus OKLab matrix drift. Without it,
 * the result can sit on the strict surface where the round-trip via culori's
 * `toGamut` and the area's hue re-pin can push it out by float ULPs.
 */
export function findMaxChroma(
  l: number,
  hDeg: number,
  gamut: Gamut,
  options: { iterations?: number; epsilon?: number; marginalChroma?: number } = {},
): number {
  if (l <= 0 || l >= 1) return 0;
  const iterations = options.iterations ?? 14;
  const eps = options.epsilon ?? 0;
  const marginalChroma = options.marginalChroma ?? 1e-3;

  const inGamut = (c: number): boolean => {
    const lin = oklchToLinearSrgb(l, c, hDeg);
    const target =
      gamut === "srgb"
        ? lin
        : gamut === "p3"
          ? linSrgbToLinP3(lin)
          : linSrgbToLinRec2020(lin);
    return (
      target.r >= -eps && target.r <= 1 + eps &&
      target.g >= -eps && target.g <= 1 + eps &&
      target.b >= -eps && target.b <= 1 + eps
    );
  };

  // Find an upper bound that is definitely outside. 0.5 covers Rec.2020 reds
  // (max chroma ≈ 0.4 in OKLCH); double until out, capped at 2.0 for safety.
  let hi = 0.5;
  while (inGamut(hi) && hi < 2) hi *= 2;
  let lo = 0;
  for (let i = 0; i < iterations; i++) {
    const mid = (lo + hi) / 2;
    if (inGamut(mid)) lo = mid;
    else hi = mid;
  }
  return Math.max(0, lo - marginalChroma);
}

/**
 * Find the OKLCH "cusp" for a given hue and gamut — the (L, C) point of
 * maximum chroma. Used by the `hsv-sv` Area mode to map (S, V) onto a fully
 * gamut-filling square: V=1, S=1 lands on the cusp; V=1, S=0 is white;
 * V=0 is black.
 *
 * Two-stage search: a 32-step coarse sweep over L, then a 20-step fine sweep
 * around the best candidate. ~52 `findMaxChroma` calls per cusp lookup,
 * which is cheap enough to call once per repaint per active hue.
 */
/**
 * Map an output format to the gamut whose surface fills the picker's area
 * and bounds the lossless saturation-preserving updates from the hue and
 * lightness sliders. OKLCH and OKLab are unbounded as serialization formats
 * but still need a finite picking gamut — Rec.2020 covers everything that
 * fits inside `<canvas colorSpace="display-p3">` plus the slice that won't
 * paint accurately on any current monitor.
 */
/**
 * Hue of an OKLCH color in HSL's hue scale (degrees). Used by the Hue slider
 * when the active format is `hsl` so the slider position matches what the
 * channel input shows — OKLCH hue and HSL hue diverge for the same color
 * (red is OKLCH ~29° but HSL 0°). Returns the OKLCH hue as a fallback when
 * the conversion fails (achromatic colors where culori returns NaN).
 */
export function hslHue(color: OklchColor): number {
  const c = toHsl({ mode: "oklch", l: color.l, c: color.c, h: color.h });
  return c?.h ?? color.h;
}

/**
 * Hue of an OKLCH color in HSB/HSV's hue scale (degrees). See `hslHue`.
 */
export function hsbHue(color: OklchColor): number {
  const c = toHsv({ mode: "oklch", l: color.l, c: color.c, h: color.h });
  return c?.h ?? color.h;
}

export function gamutFromFormat(f: ColorFormat): Gamut {
  switch (f) {
    case "hex":
    case "rgb":
    case "hsl":
    case "hsb":
      return "srgb";
    case "p3":
      return "p3";
    case "oklch":
    case "oklab":
      return "rec2020";
  }
}

export function findCusp(
  hDeg: number,
  gamut: Gamut,
): { l: number; c: number } {
  let bestL = 0.5;
  let bestC = 0;
  for (let i = 1; i < 32; i++) {
    const l = i / 32;
    const c = findMaxChroma(l, hDeg, gamut);
    if (c > bestC) {
      bestC = c;
      bestL = l;
    }
  }
  const lo = Math.max(0.001, bestL - 1 / 32);
  const hi = Math.min(0.999, bestL + 1 / 32);
  for (let i = 0; i <= 20; i++) {
    const l = lo + ((hi - lo) * i) / 20;
    const c = findMaxChroma(l, hDeg, gamut);
    if (c > bestC) {
      bestC = c;
      bestL = l;
    }
  }
  return { l: bestL, c: bestC };
}

export function gamutInfo(color: OklchColor): GamutInfo {
  const ok = { mode: "oklch" as const, ...oklchObj(color) };
  return {
    inSrgb: isInSrgb(ok),
    inP3: isInP3(ok),
    inRec2020: isInRec2020(ok),
  };
}

/**
 * Gamut-map an OKLCH color to the target gamut using CSS Color 4's
 * chroma-reduction-in-OKLCH algorithm (culori `toGamut`).
 * Returns canonical OKLCH form.
 */
export function toGamut(color: OklchColor, gamut: Gamut): OklchColor {
  return mapToGamutColor(color, gamut);
}

function mapToGamutColor(color: OklchColor, gamut: Gamut): OklchColor {
  const ok = { mode: "oklch" as const, ...oklchObj(color) };
  const targetMode = gamut === "srgb" ? "rgb" : gamut === "p3" ? "p3" : "rec2020";
  const mapper = culoriToGamut(targetMode, "oklch");
  const mapped = mapper(ok) as Color | undefined;
  if (!mapped) return color;
  const back = toOklch(mapped);
  if (!back) return color;
  return {
    l: back.l ?? color.l,
    c: Math.max(back.c ?? 0, 0),
    h: Number.isFinite(back.h) ? (back.h as number) : color.h,
    alpha: color.alpha,
  };
}

/** Composite fg (with alpha) over an opaque bg in linear-light sRGB. */
function compositeOnBg(fg: OklchColor, bg: OklchColor): OklchColor {
  if (fg.alpha >= 1) return fg;
  const fgRgb = toRgb({ mode: "oklch", ...oklchObj(fg) });
  const bgRgb = toRgb({ mode: "oklch", ...oklchObj(bg) });
  if (!fgRgb || !bgRgb) return fg;
  const a = fg.alpha;
  const out = {
    mode: "rgb" as const,
    r: (fgRgb.r ?? 0) * a + (bgRgb.r ?? 0) * (1 - a),
    g: (fgRgb.g ?? 0) * a + (bgRgb.g ?? 0) * (1 - a),
    b: (fgRgb.b ?? 0) * a + (bgRgb.b ?? 0) * (1 - a),
    alpha: 1,
  };
  const oklch = toOklch(out)!;
  return {
    l: oklch.l ?? 0,
    c: Math.max(oklch.c ?? 0, 0),
    h: Number.isFinite(oklch.h) ? (oklch.h as number) : 0,
    alpha: 1,
  };
}

export function contrast(fg: OklchColor, bg: OklchColor): ContrastResult {
  const composedFg = compositeOnBg(fg, { ...bg, alpha: 1 });
  const fgC = toRgb({ mode: "oklch", ...oklchObj(composedFg) });
  const bgC = toRgb({ mode: "oklch", ...oklchObj({ ...bg, alpha: 1 }) });
  const ratio = fgC && bgC ? wcagContrast(fgC, bgC) : 1;
  const safe = Number.isFinite(ratio) ? ratio : 1;
  return {
    wcag: round(safe, 2),
    wcagLevel: {
      aaNormal: safe >= 4.5,
      aaLarge: safe >= 3,
      aaaNormal: safe >= 7,
      aaaLarge: safe >= 4.5,
    },
    apca: apcaContrast(composedFg, { ...bg, alpha: 1 }),
  };
}

/**
 * APCA Lc value per APCA-W3 0.1.9 (SACAM 0.98G).
 * Reference: https://github.com/Myndex/SAPC-APCA
 * Returned value is rounded to 2 decimals.
 *  - Positive Lc: dark text on light bg
 *  - Negative Lc: light text on dark bg
 */
export function apcaContrast(fg: OklchColor, bg: OklchColor): number {
  const fgRgb = toRgb({ mode: "oklch", ...oklchObj(fg) });
  const bgRgb = toRgb({ mode: "oklch", ...oklchObj(bg) });
  if (!fgRgb || !bgRgb) return 0;

  const Ytxt = sapcLuminance(fgRgb.r ?? 0, fgRgb.g ?? 0, fgRgb.b ?? 0);
  const Ybg = sapcLuminance(bgRgb.r ?? 0, bgRgb.g ?? 0, bgRgb.b ?? 0);

  return round(sapcContrast(Ytxt, Ybg), 2);
}

const SA98G = {
  mainTRC: 2.4,
  Rco: 0.2126729,
  Gco: 0.7151522,
  Bco: 0.072175,
  normBG: 0.56,
  normTXT: 0.57,
  revTXT: 0.62,
  revBG: 0.65,
  blkThrs: 0.022,
  blkClmp: 1.414,
  scaleBoW: 1.14,
  scaleWoB: 1.14,
  loBoWoffset: 0.027,
  loWoBoffset: 0.027,
  deltaYmin: 0.0005,
  loClip: 0.1,
};

function sapcLuminance(r: number, g: number, b: number): number {
  const R = clamp(r, 0, 1) ** SA98G.mainTRC;
  const G = clamp(g, 0, 1) ** SA98G.mainTRC;
  const B = clamp(b, 0, 1) ** SA98G.mainTRC;
  return SA98G.Rco * R + SA98G.Gco * G + SA98G.Bco * B;
}

function sapcContrast(Ytxt: number, Ybg: number): number {
  const txt = Ytxt < SA98G.blkThrs
    ? Ytxt + (SA98G.blkThrs - Ytxt) ** SA98G.blkClmp
    : Ytxt;
  const bg = Ybg < SA98G.blkThrs
    ? Ybg + (SA98G.blkThrs - Ybg) ** SA98G.blkClmp
    : Ybg;

  if (Math.abs(bg - txt) < SA98G.deltaYmin) return 0;

  let SAPC = 0;
  let outputContrast = 0;

  if (bg > txt) {
    // Dark text on light background
    SAPC = (bg ** SA98G.normBG - txt ** SA98G.normTXT) * SA98G.scaleBoW;
    outputContrast = SAPC < SA98G.loClip ? 0 : SAPC - SA98G.loBoWoffset;
  } else {
    // Light text on dark background
    SAPC = (bg ** SA98G.revBG - txt ** SA98G.revTXT) * SA98G.scaleWoB;
    outputContrast = SAPC > -SA98G.loClip ? 0 : SAPC + SA98G.loWoBoffset;
  }

  return outputContrast * 100;
}

function clamp(x: number, lo: number, hi: number) {
  return Math.min(Math.max(x, lo), hi);
}

function round(x: number, dp: number) {
  const f = 10 ** dp;
  return Math.round(x * f) / f;
}

import { converter, type Color } from "culori";
import type { ColorFormat, OklchColor } from "./types";
import { toGamut } from "./color";

const toOklch = converter("oklch");
const toRgb = converter("rgb");
const toHsl = converter("hsl");
const toHsv = converter("hsv");
const toOklab = converter("oklab");
const toP3 = converter("p3");

export interface ChannelDescriptor {
  /** Internal key used by setColorChannel. */
  key: string;
  /** One- or two-letter UI label (R, G, B, H, S, L, etc.). */
  label: string;
  /** Current value in display units (e.g. RGB 0–255, OKLCH L 0–100). */
  value: number;
  min: number;
  max: number;
  /** Arrow-key step. */
  step: number;
  /** Shift+arrow step. */
  bigStep: number;
  /** Decimals to render. */
  precision: number;
  /** Optional unit suffix shown after the field. */
  suffix?: string;
}

const ALPHA_DESCRIPTOR = (alpha: number): ChannelDescriptor => ({
  key: "alpha",
  label: "α",
  value: round(alpha * 100, 0),
  min: 0,
  max: 100,
  step: 1,
  bigStep: 10,
  precision: 0,
  suffix: "%",
});

/**
 * Per-format channel descriptors for the multi-field input. Hex returns an
 * empty array — render hex as a single text field instead.
 */
export function colorChannels(
  color: OklchColor,
  format: ColorFormat,
): ChannelDescriptor[] {
  switch (format) {
    case "hex":
      return [];
    case "rgb": {
      const rgb = toRgb({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      });
      const r = round((rgb?.r ?? 0) * 255, 0);
      const g = round((rgb?.g ?? 0) * 255, 0);
      const b = round((rgb?.b ?? 0) * 255, 0);
      return [
        intChannel("r", "R", r, 0, 255),
        intChannel("g", "G", g, 0, 255),
        intChannel("b", "B", b, 0, 255),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    }
    case "hsl": {
      const hsl = toHsl({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      });
      return [
        intChannel("h", "H", round(hsl?.h ?? 0, 0), 0, 360),
        intChannel("s", "S", round((hsl?.s ?? 0) * 100, 0), 0, 100, "%"),
        intChannel("l", "L", round((hsl?.l ?? 0) * 100, 0), 0, 100, "%"),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    }
    case "hsb": {
      const hsv = toHsv({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      });
      return [
        intChannel("h", "H", round(hsv?.h ?? 0, 0), 0, 360),
        intChannel("s", "S", round((hsv?.s ?? 0) * 100, 0), 0, 100, "%"),
        intChannel("b", "B", round((hsv?.v ?? 0) * 100, 0), 0, 100, "%"),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    }
    case "oklch":
      return [
        intChannel("l", "L", round(color.l * 100, 0), 0, 100, "%"),
        floatChannel("c", "C", round(color.c, 3), 0, 0.4, 0.005, 0.05, 3),
        intChannel("h", "H", round(color.h, 0), 0, 360),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    case "oklab": {
      const lab = toOklab({ mode: "oklch", ...oklchObj(color) });
      return [
        intChannel("l", "L", round((lab?.l ?? color.l) * 100, 0), 0, 100, "%"),
        floatChannel("a", "a", round(lab?.a ?? 0, 3), -0.4, 0.4, 0.005, 0.05, 3),
        floatChannel("b", "b", round(lab?.b ?? 0, 3), -0.4, 0.4, 0.005, 0.05, 3),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    }
    case "p3": {
      const p3 = toP3({
        mode: "oklch",
        ...oklchObj(toGamut(color, "p3")),
      });
      return [
        floatChannel("r", "R", round(p3?.r ?? 0, 3), 0, 1, 0.01, 0.1, 3),
        floatChannel("g", "G", round(p3?.g ?? 0, 3), 0, 1, 0.01, 0.1, 3),
        floatChannel("b", "B", round(p3?.b ?? 0, 3), 0, 1, 0.01, 0.1, 3),
        ALPHA_DESCRIPTOR(color.alpha),
      ];
    }
  }
}

/**
 * Replace one channel's value in the active format's space and convert the
 * result back to canonical OKLCH. Display-unit input (e.g. RGB 0–255, OKLCH
 * L 0–100, alpha 0–100) — colorChannels and this writer agree on units.
 */
export function setColorChannel(
  color: OklchColor,
  format: ColorFormat,
  key: string,
  value: number,
): OklchColor {
  if (key === "alpha") {
    return { ...color, alpha: clamp(value / 100, 0, 1) };
  }
  switch (format) {
    case "hex":
      // Hex isn't channel-addressable; callers should special-case it.
      return color;
    case "rgb": {
      const rgb = toRgb({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      }) ?? { r: 0, g: 0, b: 0 };
      const next = {
        ...rgb,
        [key]: clamp(value / 255, 0, 1),
        mode: "rgb" as const,
      };
      return fromCulori(next, color.alpha);
    }
    case "hsl": {
      const hsl = toHsl({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      }) ?? { h: 0, s: 0, l: 0 };
      const h = key === "h" ? wrap(value, 360) : (hsl.h ?? 0);
      const s = key === "s" ? clamp(value / 100, 0, 1) : hsl.s;
      const l = key === "l" ? clamp(value / 100, 0, 1) : hsl.l;
      return fromCulori({ mode: "hsl" as const, h, s, l }, color.alpha);
    }
    case "hsb": {
      const hsv = toHsv({
        mode: "oklch",
        ...oklchObj(toGamut(color, "srgb")),
      }) ?? { h: 0, s: 0, v: 0 };
      const h = key === "h" ? wrap(value, 360) : (hsv.h ?? 0);
      const s = key === "s" ? clamp(value / 100, 0, 1) : hsv.s;
      const v = key === "b" ? clamp(value / 100, 0, 1) : hsv.v;
      return fromCulori({ mode: "hsv" as const, h, s, v }, color.alpha);
    }
    case "oklch": {
      switch (key) {
        case "l":
          return { ...color, l: clamp(value / 100, 0, 1) };
        case "c":
          return { ...color, c: clamp(value, 0, 0.5) };
        case "h":
          return { ...color, h: wrap(value, 360) };
        default:
          return color;
      }
    }
    case "oklab": {
      const lab = toOklab({ mode: "oklch", ...oklchObj(color) }) ?? {
        l: 0,
        a: 0,
        b: 0,
      };
      const l = key === "l" ? clamp(value / 100, 0, 1) : (lab.l ?? 0);
      const a = key === "a" ? clamp(value, -0.5, 0.5) : (lab.a ?? 0);
      const b = key === "b" ? clamp(value, -0.5, 0.5) : (lab.b ?? 0);
      return fromCulori({ mode: "oklab" as const, l, a, b }, color.alpha);
    }
    case "p3": {
      const p3 = toP3({
        mode: "oklch",
        ...oklchObj(toGamut(color, "p3")),
      }) ?? { r: 0, g: 0, b: 0 };
      const next = {
        ...p3,
        [key]: clamp(value, 0, 1),
        mode: "p3" as const,
      };
      return fromCulori(next, color.alpha);
    }
  }
}

function fromCulori(c: Color, alpha: number): OklchColor {
  const ok = toOklch(c);
  if (!ok) return { l: 0, c: 0, h: 0, alpha };
  return {
    l: ok.l ?? 0,
    c: ok.c ?? 0,
    h: ok.h ?? 0,
    alpha,
  };
}

function oklchObj(c: OklchColor) {
  return { l: c.l, c: c.c, h: c.h, alpha: c.alpha };
}

function intChannel(
  key: string,
  label: string,
  value: number,
  min: number,
  max: number,
  suffix?: string,
): ChannelDescriptor {
  return {
    key,
    label,
    value,
    min,
    max,
    step: 1,
    bigStep: 10,
    precision: 0,
    suffix,
  };
}

function floatChannel(
  key: string,
  label: string,
  value: number,
  min: number,
  max: number,
  step: number,
  bigStep: number,
  precision: number,
  suffix?: string,
): ChannelDescriptor {
  return { key, label, value, min, max, step, bigStep, precision, suffix };
}

function clamp(v: number, min: number, max: number) {
  return v < min ? min : v > max ? max : v;
}

function wrap(v: number, mod: number) {
  return ((v % mod) + mod) % mod;
}

function round(v: number, precision: number) {
  const m = 10 ** precision;
  return Math.round(v * m) / m;
}

"use client";

import * as React from "react";
import {
  parseColor,
  formatColor,
  formatAll,
  gamutFromFormat,
  gamutInfo,
  contrast,
  toGamut,
} from "../lib/color";
import type {
  ColorFormat,
  ContrastResult,
  GamutInfo,
  OklchColor,
} from "../lib/types";

export type ColorComponent = "l" | "c" | "h" | "alpha";

export interface UseColorPickerProps {
  /** Controlled color value (string or canonical OklchColor). */
  value?: string | OklchColor;
  /** Initial color when uncontrolled. */
  defaultValue?: string | OklchColor;
  /**
   * Fires whenever the color changes.
   *  - `color`: canonical OKLCH form (lossless source of truth).
   *  - `formatted`: the active output format string (governed by `format`).
   *  - `formats`: every supported format pre-serialized — use `formats.hex`
   *    when you need a fallback alongside the canonical `formats.oklch`.
   */
  onValueChange?: (
    color: OklchColor,
    formatted: string,
    formats: Record<ColorFormat, string>,
  ) => void;
  /** Active output format. */
  format?: ColorFormat;
  /** Initial format when uncontrolled. */
  defaultFormat?: ColorFormat;
  onFormatChange?: (format: ColorFormat) => void;
  /**
   * Color spaces (output formats) the picker exposes. Restricts the
   * FormatSwitcher tabs and the default format. Defaults to all formats.
   */
  formats?: ColorFormat[];
  /** Background used for contrast metrics. */
  backgroundColor?: string | OklchColor;
}

export interface ColorPickerState {
  color: OklchColor;
  format: ColorFormat;
  /** Active format string (mirrors `format`). */
  formatted: string;
  /** Allowed output formats (the set restricting the FormatSwitcher). */
  formats: ColorFormat[];
  /** Pre-serialized strings for every supported format. */
  formatStrings: Record<ColorFormat, string>;
  setColor: (next: string | OklchColor) => void;
  setComponent: (key: ColorComponent, value: number) => void;
  adjustComponent: (key: ColorComponent, delta: number) => void;
  setFormat: (f: ColorFormat) => void;
  setFromString: (s: string) => boolean;
  gamut: GamutInfo;
  contrast: ContrastResult;
  background: OklchColor;
}

const ALL_FORMATS: ColorFormat[] = ["hex", "rgb", "hsl", "hsb", "oklch", "oklab", "p3"];

const BLACK: OklchColor = { l: 0, c: 0, h: 0, alpha: 1 };
const WHITE: OklchColor = { l: 1, c: 0, h: 0, alpha: 1 };

function coerce(input: string | OklchColor | undefined, fallback: OklchColor): OklchColor {
  if (!input) return fallback;
  if (typeof input === "string") {
    return parseColor(input) ?? fallback;
  }
  return input;
}

function clamp(x: number, lo: number, hi: number) {
  return Math.min(Math.max(x, lo), hi);
}

function wrapHue(h: number) {
  const m = h % 360;
  return m < 0 ? m + 360 : m;
}

const HUE_EPS = 1e-4;
function isAchromatic(c: OklchColor): boolean {
  return c.c <= HUE_EPS || c.l <= HUE_EPS || c.l >= 1 - HUE_EPS;
}

function applyComponent(c: OklchColor, key: ColorComponent, raw: number): OklchColor {
  switch (key) {
    case "l":
      return { ...c, l: clamp(raw, 0, 1) };
    case "c":
      return { ...c, c: Math.max(raw, 0) };
    case "h":
      return { ...c, h: wrapHue(raw) };
    case "alpha":
      return { ...c, alpha: clamp(raw, 0, 1) };
  }
}

export function useColorPicker(props: UseColorPickerProps = {}): ColorPickerState {
  const {
    value: controlledValue,
    defaultValue,
    onValueChange,
    format: controlledFormat,
    defaultFormat = "p3",
    onFormatChange,
    formats: formatsProp,
    backgroundColor,
  } = props;

  const formats = React.useMemo<ColorFormat[]>(
    () => (formatsProp && formatsProp.length > 0 ? formatsProp : ALL_FORMATS),
    [formatsProp],
  );
  const initialFormat = formats.includes(defaultFormat) ? defaultFormat : formats[0];

  const [internalColor, setInternalColor] = React.useState<OklchColor>(() =>
    coerce(defaultValue, BLACK),
  );
  const [internalFormat, setInternalFormat] = React.useState<ColorFormat>(initialFormat);

  const isControlledColor = controlledValue !== undefined;
  const isControlledFormat = controlledFormat !== undefined;

  // Hue is undefined for achromatic colors (c=0, pure black, pure white) so
  // any string round-trip through hex/rgb erases it. Remember the last hue
  // observed on a chromatic, mid-lightness color and substitute it back when
  // the resolved color lands on an achromatic edge — keeps the area picker
  // from snapping the hue to 0 when the user drags toward gray/black/white.
  const initialHue = coerce(defaultValue, BLACK).h || 0;
  const lastGoodHueRef = React.useRef<number>(initialHue);

  const isControlledStringInput =
    isControlledColor && typeof controlledValue === "string";
  const rawColor = isControlledColor ? coerce(controlledValue, BLACK) : internalColor;
  if (!isAchromatic(rawColor)) lastGoodHueRef.current = rawColor.h;
  // Only substitute on string-controlled inputs: those are the ones that
  // round-trip through a CSS format and lose the hue. Object-controlled or
  // uncontrolled state already carries the hue verbatim, including explicit
  // user assignments like setComponent("h", 0) on a black/white color.
  const color: OklchColor =
    isControlledStringInput && isAchromatic(rawColor)
      ? { ...rawColor, h: lastGoodHueRef.current }
      : rawColor;
  const format = isControlledFormat ? controlledFormat! : internalFormat;
  const background = coerce(backgroundColor, WHITE);

  const formatStrings = React.useMemo(() => formatAll(color), [color]);
  const formatted = formatStrings[format];
  const gamut = React.useMemo(() => gamutInfo(color), [color]);
  const contrastResult = React.useMemo(
    () => contrast(color, background),
    [color, background],
  );

  // Refs that mirror `format` and `onValueChange` during render so chained
  // commits within a single event handler — e.g. `setFormat` calling
  // `commitColor` after a gamut clamp in the same tick — see the updated
  // values instead of the closure snapshot from the previous render. Without
  // this, `setFormat`'s clamp call emits `formatted` in the *old* format.
  const formatRef = React.useRef(format);
  formatRef.current = format;
  const onValueChangeRef = React.useRef(onValueChange);
  onValueChangeRef.current = onValueChange;
  const isControlledColorRef = React.useRef(isControlledColor);
  isControlledColorRef.current = isControlledColor;

  const commitColor = React.useCallback((next: OklchColor) => {
    if (!isControlledColorRef.current) setInternalColor(next);
    const cb = onValueChangeRef.current;
    if (cb) {
      const all = formatAll(next);
      cb(next, all[formatRef.current], all);
    }
  }, []);

  const setColor = React.useCallback(
    (next: string | OklchColor) => {
      const parsed = coerce(next, color);
      commitColor(parsed);
    },
    [color, commitColor],
  );

  const setComponent = React.useCallback(
    (key: ColorComponent, val: number) => {
      commitColor(applyComponent(color, key, val));
    },
    [color, commitColor],
  );

  const adjustComponent = React.useCallback(
    (key: ColorComponent, delta: number) => {
      const current =
        key === "l" ? color.l : key === "c" ? color.c : key === "h" ? color.h : color.alpha;
      commitColor(applyComponent(color, key, current + delta));
    },
    [color, commitColor],
  );

  const setFormat = React.useCallback(
    (f: ColorFormat) => {
      // Switching formats is also a switch of *picking* gamut. If the current
      // OKLCH state lives outside the new format's gamut (e.g. user authored
      // a wide P3 chroma in OKLCH mode, then toggled to hex), the displayed
      // string would be gamut-mapped at format time but the underlying state
      // — and the gamut badge — would still report out-of-gamut. Clamp on
      // the way in so state and display agree. Hue is pinned per the picker's
      // "chroma is the only lossy axis" invariant.
      const targetGamut = gamutFromFormat(f);
      const info = gamutInfo(color);
      const alreadyIn =
        targetGamut === "srgb"
          ? info.inSrgb
          : targetGamut === "p3"
            ? info.inP3
            : info.inRec2020;
      // Update the format ref first so the synchronous `commitColor` below
      // emits `formatted` in the *new* format. The state update for
      // `internalFormat` happens after the commit and would otherwise leave a
      // one-call lag where the emitted formatted string is in the prior format.
      formatRef.current = f;
      if (!alreadyIn) {
        const targetHue = color.h;
        const clamped = toGamut(color, targetGamut);
        commitColor({ ...clamped, h: targetHue });
      }
      if (!isControlledFormat) setInternalFormat(f);
      onFormatChange?.(f);
    },
    [color, commitColor, isControlledFormat, onFormatChange],
  );

  const setFromString = React.useCallback(
    (s: string) => {
      const parsed = parseColor(s);
      if (!parsed) return false;
      commitColor(parsed);
      return true;
    },
    [commitColor],
  );

  return {
    color,
    format,
    formatted,
    formats,
    formatStrings,
    setColor,
    setComponent,
    adjustComponent,
    setFormat,
    setFromString,
    gamut,
    contrast: contrastResult,
    background,
  };
}

"use client";

import * as React from "react";
import type { ColorPickerState } from "./hooks/use-color-picker";

export const ColorPickerContext = React.createContext<ColorPickerState | null>(null);

export function useColorPickerContext(): ColorPickerState {
  const ctx = React.useContext(ColorPickerContext);
  if (!ctx) {
    throw new Error(
      "ColorPicker.* parts must be rendered inside <ColorPicker> (or <ColorPicker.Root>)",
    );
  }
  return ctx;
}

"use client";

import * as React from "react";
import { ColorPickerContext } from "../context";
import { useColorPicker, type UseColorPickerProps } from "../hooks/use-color-picker";
import { cn } from "@/lib/utils";

export interface RootProps
  extends UseColorPickerProps,
    Omit<React.HTMLAttributes<HTMLDivElement>, "defaultValue" | "onChange"> {
  /** When true the picker is rendered without children using the default layout. */
  asChild?: boolean;
}

export const Root = React.forwardRef<HTMLDivElement, RootProps>(function Root(
  {
    value,
    defaultValue,
    onValueChange,
    format,
    defaultFormat,
    onFormatChange,
    formats,
    backgroundColor,
    className,
    children,
    ...rest
  },
  ref,
) {
  const state = useColorPicker({
    value,
    defaultValue,
    onValueChange,
    format,
    defaultFormat,
    onFormatChange,
    formats,
    backgroundColor,
  });

  return (
    <ColorPickerContext.Provider value={state}>
      <div
        ref={ref}
        data-slot="color-picker"
        className={cn(
          "flex w-full max-w-[280px] flex-col gap-2 rounded-lg border border-border bg-popover p-3 text-popover-foreground shadow-sm",
          className,
        )}
        {...rest}
      >
        {children}
      </div>
    </ColorPickerContext.Provider>
  );
});

"use client";

import * as React from "react";
import { useColorPickerContext } from "../context";
import {
  findCusp,
  findMaxChroma,
  formatColor,
  gamutFromFormat as libGamutFromFormat,
  gamutSignedDistance,
  linSrgbToLinP3,
  oklchToLinearSrgb,
  toGamut,
} from "../lib/color";
import type { Gamut, OklchColor } from "../lib/types";
import { cn } from "@/lib/utils";

export type AreaMode = "oklch-cl" | "hsv-sv" | "oklch-hc";
export type AreaGamut = Gamut | "none";

export interface AreaProps extends React.HTMLAttributes<HTMLDivElement> {
  /**
   * What the 2D Area represents.
   *  - oklch-cl: Y = OKLCH lightness, X = chroma normalized to gamut. Perceptually uniform.
   *    Top row is white-ish (max chroma at L=1 is 0). Most-saturated colors live at mid-Y.
   *  - hsv-sv: Y = HSV-style "value", X = saturation. OKHSV-like — anchored to the gamut
   *    cusp so top-right corner is fully saturated (Photoshop/Framer feel).
   *  - oklch-hc: X = hue, Y = chroma normalized (lightness picked separately).
   */
  mode?: AreaMode;
  /**
   * Ignored when `gamut` is "srgb" / "p3" / "rec2020" — chroma fills the
   * square up to the gamut surface. Only meaningful when `gamut === "none"`,
   * where it bounds the absolute-chroma X axis.
   */
  chromaMax?: number;
  /**
   * Render gamut. The square is filled with in-gamut colors up to this
   * gamut's surface, and warning lines mark narrower-gamut cutoffs inside.
   * Defaults to the gamut implied by the active output format
   * (hex/rgb/hsl/hsb → srgb, p3 → p3, oklch/oklab → rec2020).
   * Pass "none" to disable warping and paint the raw OKLCH plane up to
   * `chromaMax` (no fill warp, no lines).
   */
  gamut?: AreaGamut;
  /**
   * Show the gamut-cutoff warning lines drawn inside the active render gamut.
   * Defaults to true. Setting to false hides them regardless of `gamut` —
   * useful for a quieter visual when the badge already conveys gamut status.
   * No effect when `gamut` is "srgb" or "none" (nothing to draw anyway).
   */
  showWarningLines?: boolean;
  /** Render resolution of the gradient canvas. Higher = sharper, slower. Default 160. */
  resolution?: number;
  /**
   * Soft-proof out-of-display colors instead of per-channel clipping them.
   * When the active render gamut exceeds the display's (e.g. `gamut="rec2020"`
   * on a P3 monitor), pixels past the display gamut are chroma-reduced in
   * OKLCH to the display surface — preserving hue and lightness, flattening
   * chroma. The default (false) preserves the legacy per-channel clip, which
   * is cheaper but introduces hue shifts and posterization in unrenderable
   * regions. Off by default to keep first-paint cost identical to before.
   */
  softProof?: boolean;
}

/** Which gamuts get a warning line drawn inside the active render gamut. */
function warningGamuts(active: AreaGamut): Gamut[] {
  switch (active) {
    case "srgb":
    case "none":
      return [];
    case "p3":
      return ["srgb"];
    case "rec2020":
      return ["srgb", "p3"];
  }
}

/**
 * Read display-P3 support fresh on the client and re-react if the user moves
 * the window to a different display. Module-load evaluation locks the value
 * to `false` in Next.js's SSR module cache (window is undefined there), and
 * `useState(() => ...)` would diverge between server and client renders.
 * `useSyncExternalStore` returns `false` on the server (matching SSR) and the
 * real value on the client during reconciliation — no hydration mismatch.
 */
const subscribeP3 =
  typeof window !== "undefined" && typeof window.matchMedia === "function"
    ? (onChange: () => void) => {
        const mq = window.matchMedia("(color-gamut: p3)");
        mq.addEventListener("change", onChange);
        return () => mq.removeEventListener("change", onChange);
      }
    : () => () => {};
const getP3Client = () =>
  typeof window !== "undefined" &&
  typeof window.matchMedia === "function" &&
  window.matchMedia("(color-gamut: p3)").matches;
const getP3Server = () => false;

export const Area = React.forwardRef<HTMLDivElement, AreaProps>(function Area(
  {
    mode = "oklch-cl",
    chromaMax = 0.4,
    gamut: gamutProp,
    showWarningLines = true,
    resolution = 160,
    softProof = false,
    className,
    ...rest
  },
  ref,
) {
  const { color, setColor, format } = useColorPickerContext();
  const supportsP3 = React.useSyncExternalStore(
    subscribeP3,
    getP3Client,
    getP3Server,
  );
  const gamut: AreaGamut = gamutProp ?? libGamutFromFormat(format);
  const canvasRef = React.useRef<HTMLCanvasElement | null>(null);
  const containerRef = React.useRef<HTMLDivElement | null>(null);
  const [paths, setPaths] = React.useState<string[][]>([]);
  // Bead position override. The (X, Y) → OKLCH mapping is lossy at the
  // gamut poles: at l=0 or l=1 every X collapses to chroma 0, so deriving
  // the bead back from the resulting color always recovers X=0 — making
  // the bead jump to the left edge when the pointer drags past the top or
  // bottom. We keep the user's last picked (xn, yn) and render the bead
  // there. Cleared whenever color changes from a source other than our
  // own moveTo (e.g. swatch click, controlled value, input typing).
  const [pickPos, setPickPos] = React.useState<[number, number] | null>(null);
  const selfSetRef = React.useRef(false);

  React.useImperativeHandle(ref, () => containerRef.current as HTMLDivElement);

  // Adjusting state during rendering — React-blessed alternative to
  // syncing color → pickPos in a useEffect. We compare channel values
  // (not the OKLCH object identity, which a controlled ColorPicker may
  // re-create each render even when values are unchanged) against the
  // previous render's snapshot. When the user-driven path moved the
  // bead, `selfSetRef` short-circuits the clear so the override sticks.
  const [prevColor, setPrevColor] = React.useState(color);
  if (
    prevColor.l !== color.l ||
    prevColor.c !== color.c ||
    prevColor.h !== color.h ||
    prevColor.alpha !== color.alpha
  ) {
    setPrevColor(color);
    if (selfSetRef.current) {
      selfSetRef.current = false;
    } else if (pickPos !== null) {
      setPickPos(null);
    }
  }

  // The gradient and warning lines depend only on the axis the mode keeps
  // *fixed* (hue for oklch-cl/hsv-sv, lightness for oklch-hc). Depending on
  // every channel of `color` would trigger a 25 600-pixel canvas repaint plus
  // a 128² marching-squares pass on every pointer tick — enough to stall the
  // bead. Narrowing the dep to the locked axis keeps drags free.
  const fixedAxisValue = mode === "oklch-hc" ? color.l : color.h;
  React.useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;
    const w = resolution;
    const h = resolution;
    canvas.width = w;
    canvas.height = h;
    const ctx2dOpts: CanvasRenderingContext2DSettings = supportsP3
      ? { colorSpace: "display-p3" }
      : {};
    const ctx = canvas.getContext("2d", ctx2dOpts);
    if (!ctx) return;
    const img = ctx.createImageData(w, h);
    paintGradient(img, w, h, mode, color, chromaMax, gamut, supportsP3, softProof);
    ctx.putImageData(img, 0, 0);
    if (gamut === "none" || !showWarningLines) {
      setPaths([]);
    } else {
      setPaths(
        warningGamuts(gamut).map((g) =>
          computeGamutPaths(mode, color, chromaMax, g, gamut),
        ),
      );
    }
    // `color` is intentionally omitted — gradient + warning lines depend only
    // on the locked axis (`fixedAxisValue`), not on every channel of `color`.
    // Repainting on every pointer tick would stall the bead.
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [mode, fixedAxisValue, chromaMax, gamut, showWarningLines, resolution, softProof, supportsP3]);

  const [derivedPx, derivedPy] = positionFor(mode, color, chromaMax, gamut);
  const [px, py] = pickPos ?? [derivedPx, derivedPy];

  const moveTo = React.useCallback(
    (x: number, y: number) => {
      const xn = clamp01(x);
      const yn = clamp01(y);
      const next = sampleAt(mode, color, chromaMax, gamut, xn, yn);
      setPickPos([xn, yn]);
      selfSetRef.current = true;
      // With warping every (X, Y) is in-gamut by construction, so toGamut is
      // defensive only — guards against drift at numerical boundaries. When
      // gamut === "none" the user has explicitly opted out of warping and we
      // skip clamping entirely (raw OKLCH plane).
      if (gamut !== "none") {
        const targetHue = next.h;
        const clamped = toGamut(next, gamut as Gamut);
        setColor({ ...clamped, h: targetHue });
      } else {
        setColor(next);
      }
    },
    [mode, chromaMax, color, setColor, gamut],
  );

  const handlePointer = React.useCallback(
    (clientX: number, clientY: number) => {
      const el = containerRef.current;
      if (!el) return;
      const rect = el.getBoundingClientRect();
      moveTo((clientX - rect.left) / rect.width, (clientY - rect.top) / rect.height);
    },
    [moveTo],
  );

  const onPointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    (e.currentTarget as HTMLDivElement).setPointerCapture(e.pointerId);
    handlePointer(e.clientX, e.clientY);
  };
  const onPointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (e.buttons !== 1) return;
    handlePointer(e.clientX, e.clientY);
  };
  const releaseCapture = (e: React.PointerEvent<HTMLDivElement>) => {
    const el = e.currentTarget as HTMLDivElement;
    if (el.hasPointerCapture(e.pointerId)) el.releasePointerCapture(e.pointerId);
  };

  const onKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    const big = e.shiftKey ? 10 : 1;
    const stepX = big / 100; // % of axis
    const stepY = big / 100;
    let nx = px;
    let ny = py;
    switch (e.key) {
      case "ArrowLeft":
        nx -= stepX;
        break;
      case "ArrowRight":
        nx += stepX;
        break;
      case "ArrowUp":
        ny -= stepY;
        break;
      case "ArrowDown":
        ny += stepY;
        break;
      case "Home":
        nx = 0;
        break;
      case "End":
        nx = 1;
        break;
      case "PageUp":
        ny -= 0.1;
        break;
      case "PageDown":
        ny += 0.1;
        break;
      default:
        return;
    }
    e.preventDefault();
    moveTo(nx, ny);
  };

  const valueText = ariaValueTextFor(mode, color, chromaMax, gamut);

  return (
    <div
      ref={containerRef}
      data-slot="color-picker-area"
      role="application"
      aria-label="Color area"
      aria-roledescription="2D color area, use arrow keys to adjust"
      aria-valuetext={valueText}
      tabIndex={0}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={releaseCapture}
      onPointerCancel={releaseCapture}
      onKeyDown={onKeyDown}
      className={cn(
        "relative h-45 w-full cursor-crosshair overflow-hidden rounded-md border border-border outline-none touch-none select-none",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-popover",
        className,
      )}
      {...rest}
    >
      <canvas
        ref={canvasRef}
        className="block h-full w-full"
        aria-hidden="true"
      />
      {paths.length > 0 && (
        <svg
          aria-hidden="true"
          className="pointer-events-none absolute inset-0 h-full w-full"
          viewBox="0 0 1 1"
          preserveAspectRatio="none"
        >
          {paths.map((groupPaths, gi) =>
            groupPaths.map((d, i) => (
              <g key={`${gi}-${i}`}>
                <path
                  d={d}
                  fill="none"
                  stroke="rgba(0,0,0,0.55)"
                  strokeWidth={3}
                  strokeLinejoin="round"
                  strokeLinecap="round"
                  vectorEffect="non-scaling-stroke"
                />
                <path
                  d={d}
                  fill="none"
                  stroke="rgba(255,255,255,0.6)"
                  strokeWidth={1}
                  strokeLinejoin="round"
                  strokeLinecap="round"
                  vectorEffect="non-scaling-stroke"
                />
              </g>
            )),
          )}
        </svg>
      )}
      <div
        className="pointer-events-none absolute size-4 -translate-x-1/2 -translate-y-1/2 rounded-full border-2 border-white shadow-[0_0_0_1.5px_rgba(0,0,0,0.6)]"
        style={{
          left: `${px * 100}%`,
          top: `${py * 100}%`,
          background: formatColor({ ...color, alpha: 1 }, "oklch"),
        }}
      />
    </div>
  );
});

function clamp01(x: number) {
  return x < 0 ? 0 : x > 1 ? 1 : x;
}

function positionFor(
  mode: AreaMode,
  c: OklchColor,
  chromaMax: number,
  gamut: AreaGamut,
): [number, number] {
  if (gamut === "none") {
    switch (mode) {
      case "oklch-cl":
        return [clamp01(c.c / chromaMax), clamp01(1 - c.l)];
      case "hsv-sv": {
        const v = c.l;
        const s = v > 0 ? c.c / Math.max(v * chromaMax, 1e-6) : 0;
        return [clamp01(s), clamp01(1 - v)];
      }
      case "oklch-hc":
        return [
          clamp01((((c.h % 360) + 360) % 360) / 360),
          clamp01(1 - c.c / chromaMax),
        ];
    }
  }
  switch (mode) {
    case "oklch-cl": {
      const maxC = findMaxChroma(c.l, c.h, gamut as Gamut);
      const safeMaxC = maxC > 1e-6 ? maxC : 1e-6;
      return [clamp01(c.c / safeMaxC), clamp01(1 - c.l)];
    }
    case "hsv-sv": {
      const cusp = findCusp(c.h, gamut as Gamut);
      // L = V·(1 − S·(1 − Lc)), C = V·S·Cc → solve for V, S.
      const V = clamp01(c.l + (c.c * (1 - cusp.l)) / Math.max(cusp.c, 1e-6));
      const S = V > 1e-6 ? clamp01(c.c / (V * Math.max(cusp.c, 1e-6))) : 0;
      return [S, clamp01(1 - V)];
    }
    case "oklch-hc": {
      const maxC = findMaxChroma(c.l, c.h, gamut as Gamut);
      const safeMaxC = maxC > 1e-6 ? maxC : 1e-6;
      return [
        clamp01((((c.h % 360) + 360) % 360) / 360),
        clamp01(1 - c.c / safeMaxC),
      ];
    }
  }
}

/**
 * Build the OKLCH color for a normalized (x, y) inside the area, given the
 * locked axis on `base`. Mirror of `positionFor`.
 */
function sampleAt(
  mode: AreaMode,
  base: OklchColor,
  chromaMax: number,
  gamut: AreaGamut,
  xn: number,
  yn: number,
): OklchColor {
  if (gamut === "none") {
    switch (mode) {
      case "oklch-cl":
        return { ...base, c: xn * chromaMax, l: 1 - yn };
      case "hsv-sv": {
        const v = 1 - yn;
        return { ...base, l: v, c: xn * v * chromaMax };
      }
      case "oklch-hc":
        return { ...base, h: xn * 360, c: (1 - yn) * chromaMax };
    }
  }
  switch (mode) {
    case "oklch-cl": {
      const l = 1 - yn;
      const maxC = findMaxChroma(l, base.h, gamut as Gamut);
      return { ...base, l, c: xn * maxC };
    }
    case "hsv-sv": {
      const cusp = findCusp(base.h, gamut as Gamut);
      const V = 1 - yn;
      const S = xn;
      const l = V * (1 - S * (1 - cusp.l));
      const c = V * S * cusp.c;
      return { ...base, l, c };
    }
    case "oklch-hc": {
      const h = xn * 360;
      const maxC = findMaxChroma(base.l, h, gamut as Gamut);
      return { ...base, h, c: (1 - yn) * maxC };
    }
  }
}

function ariaValueTextFor(
  mode: AreaMode,
  c: OklchColor,
  chromaMax: number,
  gamut: AreaGamut,
): string {
  switch (mode) {
    case "oklch-cl": {
      const maxC =
        gamut === "none"
          ? chromaMax
          : findMaxChroma(c.l, c.h, gamut as Gamut) || chromaMax;
      return `Lightness ${(c.l * 100).toFixed(0)} percent, chroma ${c.c.toFixed(2)} of ${maxC.toFixed(2)}, hue ${c.h.toFixed(0)} degrees`;
    }
    case "hsv-sv": {
      if (gamut === "none") {
        const v = c.l;
        const s = (c.c / Math.max(v * chromaMax, 1e-6)) * 100 || 0;
        return `Saturation ${s.toFixed(0)} percent, value ${(v * 100).toFixed(0)} percent, hue ${c.h.toFixed(0)} degrees`;
      }
      const cusp = findCusp(c.h, gamut as Gamut);
      const V = clamp01(c.l + (c.c * (1 - cusp.l)) / Math.max(cusp.c, 1e-6));
      const S = V > 1e-6 ? clamp01(c.c / (V * Math.max(cusp.c, 1e-6))) : 0;
      return `Saturation ${(S * 100).toFixed(0)} percent, value ${(V * 100).toFixed(0)} percent, hue ${c.h.toFixed(0)} degrees`;
    }
    case "oklch-hc": {
      const maxC =
        gamut === "none"
          ? chromaMax
          : findMaxChroma(c.l, c.h, gamut as Gamut) || chromaMax;
      return `Hue ${c.h.toFixed(0)} degrees, chroma ${c.c.toFixed(2)} of ${maxC.toFixed(2)}, lightness ${(c.l * 100).toFixed(0)} percent`;
    }
  }
}

/* ----------------------- gradient painting ----------------------- */
/* Per-paint LUT of max chroma for the moving axis. Each row (or column for
 * oklch-hc) gets one bisection so the per-pixel cost stays a single multiply.
 * When gamut === "none" we skip the LUT and paint absolute chroma up to
 * chromaMax (the legacy unwrapped plane). */

function paintGradient(
  img: ImageData,
  w: number,
  h: number,
  mode: AreaMode,
  base: OklchColor,
  chromaMax: number,
  gamut: AreaGamut,
  canvasIsP3: boolean,
  softProof: boolean,
) {
  const data = img.data;
  const ctx = buildWarpContext(mode, base, gamut, w, h);
  // Soft-proof: build a parallel max-chroma context keyed to the *display*
  // gamut. Per pixel we'll clamp chroma down to this surface so out-of-display
  // OKLCH samples render as their hue/lightness-faithful gamut-mapped twin
  // instead of a per-channel-clipped fake. Skipping the displayCtx entirely
  // when render gamut already fits inside the display avoids a useless second
  // LUT. "none" gamut opts out of warping in general, so soft-proof is a no-op.
  const displayCap: AreaGamut =
    gamut === "none"
      ? "none"
      : canvasIsP3
        ? "p3"
        : "srgb";
  const needsSoftProof =
    softProof && gamut !== "none" && isWiderThan(gamut, displayCap);
  const displayCtx: WarpContext | null = needsSoftProof
    ? buildWarpContext(mode, base, displayCap, w, h)
    : null;

  for (let yPx = 0; yPx < h; yPx++) {
    const yn = yPx / (h - 1);
    for (let xPx = 0; xPx < w; xPx++) {
      const xn = xPx / (w - 1);

      const [l, c, hue] = warpedSample(ctx, mode, base, chromaMax, xn, yn, xPx, yPx);
      const cClamped = displayCtx
        ? Math.min(c, displayMaxChroma(displayCtx, mode, l, xPx, yPx))
        : c;

      const lin = oklchToLinearSrgb(l, cClamped, hue);
      const targetLin = canvasIsP3 ? linSrgbToLinP3(lin) : lin;
      const idx = (yPx * w + xPx) * 4;
      data[idx] = clampByte(srgbEncode(targetLin.r) * 255);
      data[idx + 1] = clampByte(srgbEncode(targetLin.g) * 255);
      data[idx + 2] = clampByte(srgbEncode(targetLin.b) * 255);
      data[idx + 3] = 255;
    }
  }
}

function isWiderThan(a: AreaGamut, b: AreaGamut): boolean {
  const rank: Record<AreaGamut, number> = { none: 99, rec2020: 3, p3: 2, srgb: 1 };
  return rank[a] > rank[b];
}

/**
 * Read the display-gamut max chroma at this pixel using the soft-proof warp
 * context. For oklch-cl/oklch-hc the precomputed 1D LUT is row-/column-keyed.
 * For hsv-sv we evaluate the OKHSV-ish triangle around the locked-hue cusp:
 * chroma rises linearly from 0 at l=0 to cusp.c at l=cusp.l, then falls back
 * to 0 at l=1. That matches how `warpedSample` already builds hsv-sv samples,
 * so the clamp is consistent with the warp.
 */
function displayMaxChroma(
  ctx: WarpContext,
  mode: AreaMode,
  l: number,
  xPx: number,
  yPx: number,
): number {
  switch (ctx.kind) {
    case "none":
      return Number.POSITIVE_INFINITY;
    case "lut-y":
      return ctx.lut[yPx];
    case "lut-x":
      return ctx.lut[xPx];
    case "cusp": {
      if (mode !== "hsv-sv") return Number.POSITIVE_INFINITY;
      const { l: cl, c: cc } = ctx.cusp;
      if (l <= cl) return cc * (l / Math.max(cl, 1e-6));
      return cc * ((1 - l) / Math.max(1 - cl, 1e-6));
    }
  }
}

/**
 * Per-paint warp resources. For oklch-cl and oklch-hc we precompute a 1D
 * max-chroma LUT keyed by the moving axis. For hsv-sv we precompute the
 * (locked-hue) cusp once. For "none" we hold no resources — the legacy raw
 * mapping uses chromaMax directly.
 */
type WarpContext =
  | { kind: "none" }
  | { kind: "lut-y"; lut: Float32Array }
  | { kind: "lut-x"; lut: Float32Array }
  | { kind: "cusp"; cusp: { l: number; c: number } };

function buildWarpContext(
  mode: AreaMode,
  base: OklchColor,
  gamut: AreaGamut,
  w: number,
  h: number,
): WarpContext {
  if (gamut === "none") return { kind: "none" };
  switch (mode) {
    case "oklch-cl": {
      const lut = new Float32Array(h);
      for (let j = 0; j < h; j++) {
        const l = 1 - j / (h - 1);
        lut[j] = findMaxChroma(l, base.h, gamut as Gamut);
      }
      return { kind: "lut-y", lut };
    }
    case "oklch-hc": {
      const lut = new Float32Array(w);
      for (let i = 0; i < w; i++) {
        const hue = (i / (w - 1)) * 360;
        lut[i] = findMaxChroma(base.l, hue, gamut as Gamut);
      }
      return { kind: "lut-x", lut };
    }
    case "hsv-sv":
      return { kind: "cusp", cusp: findCusp(base.h, gamut as Gamut) };
  }
}

/**
 * Read (l, c, hue) for a normalized (xn, yn) using the precomputed warp
 * context. `xPx`/`yPx` index into the LUT for oklch-cl/oklch-hc; hsv-sv and
 * "none" don't use them.
 */
function warpedSample(
  ctx: WarpContext,
  mode: AreaMode,
  base: OklchColor,
  chromaMax: number,
  xn: number,
  yn: number,
  xPx: number,
  yPx: number,
): [number, number, number] {
  if (ctx.kind === "none") {
    const ok = sampleRaw(mode, base, chromaMax, xn, yn);
    return [ok.l, ok.c, ok.h];
  }
  switch (mode) {
    case "oklch-cl": {
      const l = 1 - yn;
      const maxC = (ctx as { kind: "lut-y"; lut: Float32Array }).lut[yPx];
      return [l, xn * maxC, base.h];
    }
    case "hsv-sv": {
      const cusp = (ctx as { kind: "cusp"; cusp: { l: number; c: number } }).cusp;
      const V = 1 - yn;
      const S = xn;
      const l = V * (1 - S * (1 - cusp.l));
      const c = V * S * cusp.c;
      return [l, c, base.h];
    }
    case "oklch-hc": {
      const hue = xn * 360;
      const maxC = (ctx as { kind: "lut-x"; lut: Float32Array }).lut[xPx];
      return [base.l, (1 - yn) * maxC, hue];
    }
  }
}

function sampleRaw(
  mode: AreaMode,
  base: OklchColor,
  chromaMax: number,
  xn: number,
  yn: number,
): { l: number; c: number; h: number } {
  switch (mode) {
    case "oklch-cl":
      return { l: 1 - yn, c: xn * chromaMax, h: base.h };
    case "hsv-sv": {
      const v = 1 - yn;
      return { l: v, c: xn * v * chromaMax, h: base.h };
    }
    case "oklch-hc":
      return { l: base.l, c: (1 - yn) * chromaMax, h: xn * 360 };
  }
}

/**
 * Compute a warning gamut's boundary inside the *active render gamut's* warped
 * coordinate space, as SVG path strings in normalized 0..1 coords. Marching
 * squares on a 128² grid where each cell samples gamutSignedDistance against
 * the warning gamut, with sample positions warped through the active gamut's
 * max-chroma so the line lands on the correct (X, Y) inside the filled square.
 */
function computeGamutPaths(
  mode: AreaMode,
  base: OklchColor,
  chromaMax: number,
  warningGamut: Gamut,
  activeGamut: AreaGamut,
): string[] {
  const N = 128;
  const stride = N + 1;
  const sd = new Float32Array(stride * stride);
  // Precompute hsv-sv's cusp once; without this the 16 384 grid samples would
  // each rebuild it (52 findMaxChroma calls each → ~850 K total).
  const cusp =
    mode === "hsv-sv" && activeGamut !== "none"
      ? findCusp(base.h, activeGamut as Gamut)
      : null;
  for (let j = 0; j <= N; j++) {
    const yn = j / N;
    for (let i = 0; i <= N; i++) {
      const xn = i / N;
      const ok =
        activeGamut === "none"
          ? sampleRaw(mode, base, chromaMax, xn, yn)
          : sampleWarpedForLine(mode, base, activeGamut as Gamut, xn, yn, cusp);
      sd[j * stride + i] = gamutSignedDistance(
        { l: ok.l, c: ok.c, h: ok.h, alpha: 1 },
        warningGamut,
      );
    }
  }

  const interp = (
    ax: number, ay: number, av: number,
    bx: number, by: number, bv: number,
  ): [number, number] => {
    const t = av / (av - bv);
    return [ax + (bx - ax) * t, ay + (by - ay) * t];
  };

  const segs: number[] = []; // flat: [ax, ay, bx, by, ax, ay, bx, by, ...]
  const pushSeg = (a: [number, number], b: [number, number]) => {
    if (a[0] === b[0] && a[1] === b[1]) return;
    segs.push(a[0], a[1], b[0], b[1]);
  };
  for (let j = 0; j < N; j++) {
    for (let i = 0; i < N; i++) {
      const aTL = sd[j * stride + i];
      const aTR = sd[j * stride + i + 1];
      const aBL = sd[(j + 1) * stride + i];
      const aBR = sd[(j + 1) * stride + i + 1];
      const code =
        (aTL > 0 ? 8 : 0) |
        (aTR > 0 ? 4 : 0) |
        (aBR > 0 ? 2 : 0) |
        (aBL > 0 ? 1 : 0);
      if (code === 0 || code === 15) continue;
      const x0 = i / N;
      const y0 = j / N;
      const x1 = (i + 1) / N;
      const y1 = (j + 1) / N;
      const top = () => interp(x0, y0, aTL, x1, y0, aTR);
      const right = () => interp(x1, y0, aTR, x1, y1, aBR);
      const bottom = () => interp(x0, y1, aBL, x1, y1, aBR);
      const left = () => interp(x0, y0, aTL, x0, y1, aBL);
      switch (code) {
        case 1: case 14: pushSeg(left(), bottom()); break;
        case 2: case 13: pushSeg(bottom(), right()); break;
        case 3: case 12: pushSeg(left(), right()); break;
        case 4: case 11: pushSeg(top(), right()); break;
        case 6: case 9:  pushSeg(top(), bottom()); break;
        case 7: case 8:  pushSeg(left(), top()); break;
        case 5:  pushSeg(left(), top()); pushSeg(bottom(), right()); break;
        case 10: pushSeg(left(), bottom()); pushSeg(top(), right()); break;
      }
    }
  }

  const segCount = segs.length / 4;
  if (segCount === 0) return [];

  // Build endpoint map keyed by quantized coords. Endpoints from adjacent cells
  // share the same `interp` inputs along their shared edge, so they collide
  // exactly — quantization only protects against float ULP drift.
  const Q = 1_000_000;
  const key = (x: number, y: number) => `${(x * Q) | 0},${(y * Q) | 0}`;
  type Endpoint = { seg: number; end: 0 | 1 };
  const endpointMap = new Map<string, Endpoint[]>();
  const addEp = (k: string, e: Endpoint) => {
    const arr = endpointMap.get(k);
    if (arr) arr.push(e);
    else endpointMap.set(k, [e]);
  };
  for (let s = 0; s < segCount; s++) {
    const o = s * 4;
    addEp(key(segs[o], segs[o + 1]), { seg: s, end: 0 });
    addEp(key(segs[o + 2], segs[o + 3]), { seg: s, end: 1 });
  }

  const used = new Uint8Array(segCount);
  const popEndpointAt = (k: string): Endpoint | null => {
    const arr = endpointMap.get(k);
    if (!arr) return null;
    while (arr.length > 0) {
      const e = arr.pop()!;
      if (!used[e.seg]) return e;
    }
    return null;
  };

  const polylines: number[][] = [];
  for (let start = 0; start < segCount; start++) {
    if (used[start]) continue;
    used[start] = 1;
    const o = start * 4;
    const pts: number[] = [segs[o], segs[o + 1], segs[o + 2], segs[o + 3]];

    // Extend forward off the tail.
    while (true) {
      const tx = pts[pts.length - 2];
      const ty = pts[pts.length - 1];
      const e = popEndpointAt(key(tx, ty));
      if (!e) break;
      used[e.seg] = 1;
      const no = e.seg * 4;
      if (e.end === 0) pts.push(segs[no + 2], segs[no + 3]);
      else pts.push(segs[no], segs[no + 1]);
    }
    // Extend backward off the head.
    while (true) {
      const hx = pts[0];
      const hy = pts[1];
      const e = popEndpointAt(key(hx, hy));
      if (!e) break;
      used[e.seg] = 1;
      const no = e.seg * 4;
      if (e.end === 0) pts.unshift(segs[no + 2], segs[no + 3]);
      else pts.unshift(segs[no], segs[no + 1]);
    }

    polylines.push(pts);
  }

  const fmt = (v: number) => v.toFixed(5);
  return polylines.map((pts) => {
    const last = pts.length;
    const closed =
      last >= 4 && pts[0] === pts[last - 2] && pts[1] === pts[last - 1];
    let d = `M${fmt(pts[0])},${fmt(pts[1])}`;
    for (let i = 2; i < last; i += 2) {
      d += `L${fmt(pts[i])},${fmt(pts[i + 1])}`;
    }
    if (closed) d += "Z";
    return d;
  });
}

/**
 * Sample helper for the warning-line marching squares. Mirrors `sampleAt`
 * but takes raw inputs (no `gamut === "none"` branch — callers handle it).
 * `cusp` is required for hsv-sv mode; precomputed by the caller for speed.
 */
function sampleWarpedForLine(
  mode: AreaMode,
  base: OklchColor,
  activeGamut: Gamut,
  xn: number,
  yn: number,
  cusp: { l: number; c: number } | null,
): { l: number; c: number; h: number } {
  switch (mode) {
    case "oklch-cl": {
      const l = 1 - yn;
      const maxC = findMaxChroma(l, base.h, activeGamut);
      return { l, c: xn * maxC, h: base.h };
    }
    case "hsv-sv": {
      const k = cusp ?? findCusp(base.h, activeGamut);
      const V = 1 - yn;
      const S = xn;
      const l = V * (1 - S * (1 - k.l));
      const c = V * S * k.c;
      return { l, c, h: base.h };
    }
    case "oklch-hc": {
      const h = xn * 360;
      const maxC = findMaxChroma(base.l, h, activeGamut);
      return { l: base.l, c: (1 - yn) * maxC, h };
    }
  }
}

function srgbEncode(v: number) {
  const x = v < 0 ? 0 : v > 1 ? 1 : v;
  return x <= 0.0031308 ? 12.92 * x : 1.055 * Math.pow(x, 1 / 2.4) - 0.055;
}

function clampByte(x: number) {
  return x < 0 ? 0 : x > 255 ? 255 : Math.round(x);
}

"use client";

import * as React from "react";
import { useColorPickerContext } from "../context";
import {
  findMaxChroma,
  gamutFromFormat,
  hslHue,
  hsbHue,
} from "../lib/color";
import { setColorChannel } from "../lib/channels";
import { cn } from "@/lib/utils";

export interface HueProps extends Omit<React.HTMLAttributes<HTMLDivElement>, "onKeyDown"> {
  orientation?: "horizontal" | "vertical";
}

export const Hue = React.forwardRef<HTMLDivElement, HueProps>(function Hue(
  { orientation = "horizontal", className, ...rest },
  ref,
) {
  const { color, format, setColor } = useColorPickerContext();

  // Slider tracks the active format's hue scale so the position matches the
  // value shown in ChannelInput. OKLCH hue ≠ HSL/HSB hue for the same color
  // (red is OKLCH ~29° / HSL 0°), so an OKLCH-driven slider feels broken to
  // users editing in HSL/HSB. For formats without a hue channel (hex, rgb,
  // p3, oklab) we fall back to OKLCH hue.
  const usesFormatHue = format === "hsl" || format === "hsb";
  const displayedHue = React.useMemo(() => {
    if (format === "hsl") return hslHue(color);
    if (format === "hsb") return hsbHue(color);
    return color.h;
  }, [format, color]);
  const trackRef = React.useRef<HTMLDivElement | null>(null);
  React.useImperativeHandle(ref, () => trackRef.current as HTMLDivElement);

  // When the hue changes, max chroma at (L, H, gamut) changes too. Preserving
  // absolute chroma would push the color out of the active gamut as the user
  // scrolls into a more constrained hue (e.g. green has less max chroma than
  // red in P3). Preserve "saturation" — the bead's X position in the area —
  // by rescaling chroma to the new hue's max. The bead stays put; the badge
  // stays green.
  const commitHue = React.useCallback(
    (newH: number) => {
      const wrapped = ((newH % 360) + 360) % 360;
      // HSL/HSB: write hue through the active format so the channel input's
      // H value matches the slider exactly (no OKLCH↔HSL hue drift).
      if (usesFormatHue) {
        setColor(setColorChannel(color, format, "h", wrapped));
        return;
      }
      // OKLCH path: rescale chroma to preserve "saturation" — the bead's X
      // position in the area — as max chroma at (L, H, gamut) shifts with
      // hue (e.g. green has less max chroma than red in P3).
      const gamut = gamutFromFormat(format);
      const oldMaxC = findMaxChroma(color.l, color.h, gamut);
      const newMaxC = findMaxChroma(color.l, wrapped, gamut);
      const saturation = oldMaxC > 1e-6 ? color.c / oldMaxC : 0;
      const nextC = saturation * newMaxC;
      setColor({ ...color, h: wrapped, c: nextC });
    },
    [color, format, setColor, usesFormatHue],
  );

  const moveTo = (clientCoord: number) => {
    const el = trackRef.current;
    if (!el) return;
    const rect = el.getBoundingClientRect();
    const ratio =
      orientation === "horizontal"
        ? (clientCoord - rect.left) / rect.width
        : (clientCoord - rect.top) / rect.height;
    const clamped = Math.max(0, Math.min(1, ratio));
    commitHue(clamped * 360);
  };

  const onPointerDown = (e: React.PointerEvent<HTMLDivElement>) => {
    (e.currentTarget as HTMLDivElement).setPointerCapture(e.pointerId);
    moveTo(orientation === "horizontal" ? e.clientX : e.clientY);
  };
  const onPointerMove = (e: React.PointerEvent<HTMLDivElement>) => {
    if (e.buttons !== 1) return;
    moveTo(orientation === "horizontal" ? e.clientX : e.clientY);
  };
  const releaseCapture = (e: React.PointerEvent<HTMLDivElement>) => {
    const el = e.currentTarget as HTMLDivElement;
    if (el.hasPointerCapture(e.pointerId)) el.releasePointerCapture(e.pointerId);
  };

  const onKeyDown = (e: React.KeyboardEvent<HTMLDivElement>) => {
    const big = e.shiftKey ? 10 : 1;
    let next = displayedHue;
    switch (e.key) {
      case "ArrowLeft":
      case "ArrowDown":
        next -= big;
        break;
      case "ArrowRight":
      case "ArrowUp":
        next += big;
        break;
      case "Home":
        next = 0;
        break;
      case "End":
        next = 360;
        break;
      case "PageUp":
        next += 25;
        break;
      case "PageDown":
        next -= 25;
        break;
      default:
        return;
    }
    e.preventDefault();
    commitHue(next);
  };

  const pos = (((displayedHue % 360) + 360) % 360) / 360;
  const isVertical = orientation === "vertical";

  return (
    <div
      ref={trackRef}
      data-slot="color-picker-hue"
      role="slider"
      aria-label="Hue"
      aria-valuemin={0}
      aria-valuemax={360}
      aria-valuenow={Math.round(displayedHue)}
      aria-valuetext={`${Math.round(displayedHue)} degrees`}
      aria-orientation={orientation}
      tabIndex={0}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={releaseCapture}
      onPointerCancel={releaseCapture}
      onKeyDown={onKeyDown}
      className={cn(
        "relative cursor-pointer rounded-full outline-none touch-none",
        isVertical ? "h-32 w-3" : "h-3 w-full",
        "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2 focus-visible:ring-offset-popover",
        className,
      )}
      style={{
        background: isVertical
          ? "linear-gradient(to bottom, oklch(0.7 0.25 0), oklch(0.7 0.25 60), oklch(0.7 0.25 120), oklch(0.7 0.25 180), oklch(0.7 0.25 240), oklch(0.7 0.25 300), oklch(0.7 0.25 360))"
          : "linear-gradient(to right, oklch(0.7 0.25 0), oklch(0.7 0.25 60), oklch(0.7 0.25 120), oklch(0.7 0.25 180), oklch(0.7 0.25 240), oklch(0.7 0.25 300), oklch(0.7 0.25 360))",
      }}
      {...rest}
    >
      <div
        className="pointer-events-none absolute size-4 -translate-x-1/2 -translate-y-1/2 rounded-full border-2 border-white shadow-[0_0_0_1.5px_rgba(0,0,0,0.6)]"
        style={
          isVertical
            ? { left: "50%", top: `calc(${pos} * (100% - 16px) + 8px)`, background: `oklch(0.7 0.25 ${displayedHue})` }
            : { left: `calc(${pos} * (100% - 16px) + 8px)`, top: "50%", background: `oklch(0.7 0.25 ${displayedHue})` }
        }
      />
    </div>
  );
});

