      data-slot="color-picker-channel-input"
      className={cn(
        "flex h-8 items-stretch overflow-hidden rounded-md border border-input bg-transparent font-mono text-xs shadow-xs",
        "focus-within:ring-1 focus-within:ring-ring",
        className,
      )}
      {...rest}
    >
      {showFormat && (
        <>
          <FormatSelect format={format} formats={formats} onChange={setFormat} />
          <Divider />
        </>
      )}
      {format === "hex" ? (
        <HexField value={formatted} onCommit={setFromString} />
      ) : (
        channels.map((ch, i) => (
          <React.Fragment key={ch.key}>
            <ChannelField
              channel={ch}
              onChange={(v) => handleChannelChange(ch.key, v)}
              onPasteColor={setFromString}
            />
            {i < channels.length - 1 && <Divider />}
          </React.Fragment>
        ))
      )}
    </div>
  );
});

/* ────────────────────── Format select ────────────────────── */

function FormatSelect({
  format,
  formats,
  onChange,
}: {
  format: ColorFormat;
  formats: ColorFormat[];
  onChange: (next: ColorFormat) => void;
}) {
  return (
    <div className="relative inline-flex shrink-0 items-center">
      <select
        data-slot="color-picker-channel-input-format"
        aria-label="Color format"
        value={format}
        onChange={(e) => onChange(e.target.value as ColorFormat)}
        className="h-full appearance-none bg-transparent pl-2 pr-5 font-mono text-xs uppercase tracking-wide outline-none"
      >
        {formats.map((f) => (
          <option key={f} value={f}>
            {f}
          </option>
        ))}
      </select>
      <svg
        aria-hidden="true"
        viewBox="0 0 12 12"
        className="pointer-events-none absolute right-1.5 size-3 text-muted-foreground"
      >
        <path
          d="M3 4.5l3 3 3-3"
          fill="none"
          stroke="currentColor"
          strokeWidth="1.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        />
      </svg>
    </div>
  );
}

/* ────────────────────── Hex single field ────────────────────── */

function HexField({
  value,
  onCommit,
}: {
  value: string;
  onCommit: (v: string) => boolean;
}) {
  // Adjusting state during rendering — React-blessed alternative to
  // syncing prop → state in useEffect. When the upstream `value` changes
  // (e.g., a sibling control commits), we re-seed the draft synchronously
  // *during* the render that observes the change, not after a paint.
  const [draft, setDraft] = React.useState(value);
  const [prevValue, setPrevValue] = React.useState(value);
  const [error, setError] = React.useState(false);
  if (value !== prevValue) {
    setPrevValue(value);
    setDraft(value);
    setError(false);
  }

  const commit = (v: string) => {
    const ok = onCommit(v.trim());
    setError(!ok);
  };

  return (
    <input
      data-slot="color-picker-channel-input-field"
      type="text"
      spellCheck={false}
      autoComplete="off"
      autoCorrect="off"
      autoCapitalize="off"
      aria-label="Hex value"
      aria-invalid={error || undefined}
      value={draft}
      onChange={(e) => {
        setDraft(e.target.value);
        setError(false);
      }}
      onBlur={(e) => commit(e.target.value)}
      onKeyDown={(e) => {
        if (e.key === "Enter") {
          e.preventDefault();
          commit(e.currentTarget.value);
        } else if (e.key === "Escape") {
          setDraft(value);
          setError(false);
        }
      }}
      className={cn(
        "min-w-0 flex-1 bg-transparent px-2 outline-none",
        error && "text-destructive",
      )}
    />
  );
}

/* ────────────────────── Numeric channel field ────────────────────── */

function ChannelField({
  channel,
  onChange,
  onPasteColor,
}: {
  channel: ChannelDescriptor;
  onChange: (next: number) => void;
  onPasteColor: (raw: string) => boolean;
}) {
  const display = formatNumber(channel.value, channel.precision);
  // Sync draft when external state updates (slider drag, sibling channel,
  // format swap) using the in-render adjustment pattern. Comparing formatted
  // strings avoids clobbering an in-progress edit when the canonical value
  // rounds to the same display string.
  const [draft, setDraft] = React.useState(display);
  const [prevDisplay, setPrevDisplay] = React.useState(display);
  if (display !== prevDisplay) {
    setPrevDisplay(display);
    setDraft(display);
  }

  const commit = (raw: string) => {
    const parsed = parseFloat(raw);
    if (Number.isNaN(parsed)) {
      setDraft(display);
      return;
    }
    onChange(parsed);
  };

  const step = (delta: number) => {
    const parsed = parseFloat(draft);
    const base = Number.isNaN(parsed) ? channel.value : parsed;
    onChange(base + delta);
  };

  return (
    <label className="relative inline-flex h-full min-w-0 flex-1 items-center">
      <span className="sr-only">{channel.label}</span>
      <input
        data-slot="color-picker-channel-input-field"
        type="text"
        inputMode="decimal"
        spellCheck={false}
        autoComplete="off"
        autoCorrect="off"
        autoCapitalize="off"
        aria-label={channel.label}
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onBlur={(e) => commit(e.target.value)}
        onPaste={(e) => {
          const text = e.clipboardData?.getData("text") ?? "";
          if (parseColor(text.trim())) {
            e.preventDefault();
            onPasteColor(text);
          }
        }}
        onKeyDown={(e) => {
          const big = e.shiftKey ? channel.bigStep : channel.step;
          if (e.key === "ArrowUp") {
            e.preventDefault();
            step(big);
          } else if (e.key === "ArrowDown") {
            e.preventDefault();
            step(-big);
          } else if (e.key === "Enter") {
            e.preventDefault();
            commit(e.currentTarget.value);
          } else if (e.key === "Escape") {
            setDraft(display);
          }
        }}
        className="w-full min-w-0 bg-transparent px-1.5 text-center outline-none tabular-nums"
      />
      {channel.suffix && (
        <span
          aria-hidden
          className="pointer-events-none pr-1.5 text-muted-foreground"
        >
          {channel.suffix}
        </span>
      )}
    </label>
  );
}

/* ────────────────────── Helpers ────────────────────── */

function Divider() {
  return <div aria-hidden className="w-px self-stretch bg-border" />;
}

function formatNumber(value: number, precision: number): string {
  return precision === 0 ? String(Math.round(value)) : value.toFixed(precision);
}

"use client";

import * as React from "react";
import { Plus } from "lucide-react";
import { useColorPickerContext } from "../context";
import { formatColor, parseColor } from "../lib/color";
import type { OklchColor } from "../lib/types";
import { cn } from "@/lib/utils";

// Inline SVG checkerboard so transparent / partially-opaque presets read as
// translucent rather than solid against the popover bg.
const CHECKERBOARD =
  "url(\"data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' width='8' height='8' viewBox='0 0 8 8'><rect width='4' height='4' fill='%23ccc'/><rect x='4' y='4' width='4' height='4' fill='%23ccc'/></svg>\")";

export interface SwatchesProps extends React.HTMLAttributes<HTMLDivElement> {
  presets?: string[];
  /**
   * When provided, renders a "+" tile after the presets that calls this with
   * the current color. The consumer owns state (lift `presets` and update it
   * here, persist to localStorage / a server / Zustand / whatever).
   */
  onAdd?: (color: OklchColor, hex: string) => void;
}

const DEFAULT_PRESETS = [
  "oklch(0.95 0 0)",
  "oklch(0.75 0 0)",
  "oklch(0.5 0 0)",
  "oklch(0.25 0 0)",
  "oklch(0.05 0 0)",
  "oklch(0.7 0.18 30)",
  "oklch(0.7 0.18 90)",
  "oklch(0.7 0.18 150)",
  "oklch(0.7 0.18 210)",
  "oklch(0.7 0.18 270)",
];

export const Swatches = React.forwardRef<HTMLDivElement, SwatchesProps>(function Swatches(
  { presets = DEFAULT_PRESETS, onAdd, className, ...rest },
  ref,
) {
  const { color, setColor } = useColorPickerContext();
  // Compare presets to the current color in canonical OKLCH form so the active
  // ring shows regardless of the user's active output format. A hex-string
  // comparison would never match when the format is anything but `hex`.
  const isSamePreset = React.useCallback(
    (preset: OklchColor) => {
      if (Math.abs(preset.l - color.l) >= 1e-3) return false;
      if (Math.abs(preset.c - color.c) >= 1e-3) return false;
      if (Math.abs(preset.alpha - color.alpha) >= 1e-3) return false;
      // Achromatic colors have an undefined hue; skip the hue check when either
      // side has near-zero chroma so swatches like `oklch(0.5 0 0)` match the
      // current gray regardless of its drifted hue.
      if (preset.c < 1e-3 || color.c < 1e-3) return true;
      const d = (((preset.h - color.h) % 360) + 360) % 360;
      const wrapped = d > 180 ? 360 - d : d;
      return wrapped < 0.1;
    },
    [color],
  );
  return (
    <div
      ref={ref}
      data-slot="color-picker-swatches"
      role="listbox"
      aria-label="Color swatches"
      className={cn("grid grid-cols-10 gap-1", className)}
      {...rest}
    >
      {presets.map((p, i) => {
        const parsed = parseColor(p);
        const active = parsed ? isSamePreset(parsed) : false;
        // Paint the swatch with the raw preset string so out-of-sRGB colors
        // (P3 / OKLCH wide-gamut) actually render in their native gamut on
        // capable displays. Hex-conversion would clamp them to sRGB.
        return (
          <button
            key={`${p}-${i}`}
            type="button"
            role="option"
            aria-selected={active}
            aria-label={p}
            onClick={() => setColor(p)}
            className={cn(
              "relative size-5 cursor-pointer overflow-hidden rounded-sm border border-border outline-none transition-transform",
              "focus-visible:ring-2 focus-visible:ring-ring hover:scale-110",
              active && "ring-2 ring-ring",
            )}
            style={{ backgroundImage: CHECKERBOARD, backgroundSize: "8px 8px" }}
          >
            <span
              aria-hidden
              className="absolute inset-0"
              style={{ background: p }}
            />
          </button>
        );
      })}
      {onAdd && (
        <button
          type="button"
          aria-label="Add current color to swatches"
          onClick={() => onAdd(color, formatColor(color, "hex"))}
          className={cn(
            "inline-flex size-5 cursor-pointer items-center justify-center rounded-sm border border-dashed border-border text-muted-foreground outline-none transition-colors",
            "hover:border-foreground hover:text-foreground focus-visible:ring-2 focus-visible:ring-ring",
          )}
        >
          <Plus className="size-3" />
        </button>
      )}
    </div>
  );
});

